import { useState } from "react";

const IMG = "data:image/jpeg;base64,";
const BUJAN = "data:image/png;base64,";

const T = {
  0: { name:"ZDARZENIE", color:"#f59e0b" },
  1: { name:"ARTEFAKT", color:"#a78bfa" },
  2: { name:"LOKACJA",  color:"#34d399" },
};

function EventIcon({size=16,color="#f59e0b"}) {
  return <svg width={size} height={size} viewBox="0 0 32 32"><path d="M18,1 L8,15 L14,15 L12,31 L24,13 L17,13Z" fill={color}/></svg>;
}
function ArtifactIcon({size=16,color="#a78bfa"}) {
  return <svg width={size} height={size} viewBox="0 0 32 32"><rect x="13" y="14" width="6" height="16" rx="1.5" fill={color}/><rect x="6" y="4" width="20" height="11" rx="2" fill={color}/><rect x="9" y="7" width="14" height="5" rx="1" fill="#06050a" opacity="0.35"/></svg>;
}
function LocationIcon({size=16,color="#34d399"}) {
  return <svg width={size} height={size} viewBox="0 0 32 32"><rect x="10" y="13" width="12" height="17" rx="1" fill={color}/><rect x="7" y="8" width="18" height="6" rx="1" fill={color}/><rect x="13" y="22" width="6" height="8" fill="#06050a" opacity="0.35"/><rect x="7" y="3" width="4" height="6" fill={color}/><rect x="14" y="3" width="4" height="6" fill={color}/><rect x="21" y="3" width="4" height="6" fill={color}/></svg>;
}
const ICONS = {0:EventIcon, 1:ArtifactIcon, 2:LocationIcon};

function HandCard({card, idx=0, total=1, selected, onClick}) {
  const t = T[card.adventureType]||T[0];
  const Icon = ICONS[card.adventureType];
  const mid=(total-1)/2; const off=idx-mid;
  const rot=selected?0:off*2.5; const ty=selected?-48:Math.abs(off)*4;

  return (
    <div onClick={onClick} className="relative cursor-pointer flex-shrink-0 group"
      style={{width:"100px",height:"140px",
        transform:`rotate(${rot}deg) translateY(${ty}px) ${selected?"scale(1.25) translateY(-46px)":""}`,
        transition:"all 0.4s cubic-bezier(0.34,1.56,0.64,1)",
        zIndex:selected?50:10+idx, marginLeft:idx>0?"-14px":"0"}}>
      
      <div className="absolute -inset-2 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none"
        style={{background:`radial-gradient(ellipse,${t.color}18,transparent 70%)`,filter:"blur(6px)"}}/>
      
      <div className="absolute inset-0 rounded-lg overflow-hidden" style={{
        border:`2px solid ${selected?t.color+"90":t.color+"30"}`,
        boxShadow:selected?`0 0 20px ${t.color}20,0 16px 40px rgba(0,0,0,0.7)`:`0 4px 14px rgba(0,0,0,0.6)`,
        background:"#0a0406"}}>
        
        {/* Full art */}
        <div className="absolute inset-0" style={{backgroundImage:`url(${card.img})`,backgroundSize:"cover",backgroundPosition:"center 25%"}}/>
        <div className="absolute inset-0" style={{background:"radial-gradient(ellipse 95% 85% at 50% 35%,transparent 30%,rgba(0,0,0,0.4) 100%)"}}/>
        <div className="absolute bottom-0 left-0 right-0" style={{height:"28%",background:"linear-gradient(transparent,rgba(5,3,8,0.92))"}}/>
        <div className="absolute top-0 left-0 right-0" style={{height:"22%",background:"linear-gradient(rgba(0,0,0,0.7),transparent)"}}/>
        
        {/* Top: NAME only, caps, dark bar */}
        <div className="absolute top-0 left-0 right-0 px-1.5 py-[5px] text-center"
          style={{background:"rgba(0,0,0,0.75)",borderBottom:`1px solid ${t.color}18`}}>
          <span className="text-[8px] font-black tracking-wider leading-tight" style={{
            color:t.color, textShadow:`0 0 10px ${t.color}30`,
            fontFamily:"Georgia,serif", letterSpacing:"0.08em",
          }}>{card.name.toUpperCase()}</span>
        </div>
        
        {/* Bottom: icon + type label */}
        <div className="absolute bottom-0 left-0 right-0 flex items-center justify-center gap-1.5 py-1.5"
          style={{background:"rgba(0,0,0,0.82)",borderRadius:"0 0 6px 6px",borderTop:`1px solid ${t.color}20`}}>
          <Icon size={14} color={t.color}/>
          <span className="text-[8px] font-bold tracking-widest" style={{color:t.color+"cc"}}>{t.name}</span>
        </div>
      </div>
    </div>
  );
}

const CARDS = [
  {id:13,name:"Trucizna",adventureType:0,img:IMG},
  {id:23,name:"Swaćba",adventureType:0,img:IMG},
  {id:4,name:"Topór Peruna",adventureType:1,img:IMG},
  {id:21,name:"Miecz Kladenet",adventureType:1,img:IMG},
  {id:57,name:"Wyspa Bujan",adventureType:2,img:BUJAN},
  {id:18,name:"Twierdza",adventureType:2,img:IMG},
];

export default function Demo() {
  const [sel, setSel] = useState(null);
  return (
    <div className="w-full min-h-screen flex flex-col items-center justify-center gap-12" style={{background:"#04030a"}}>
      <div className="flex items-end justify-center py-8">
        {CARDS.map((c,i) => (
          <HandCard key={c.id} card={c} idx={i} total={CARDS.length}
            selected={sel===c.id} onClick={()=>setSel(sel===c.id?null:c.id)}/>
        ))}
      </div>
    </div>
  );
}
